    status public."AccountStatus" DEFAULT 'ACTIVE'::public."AccountStatus" NOT NULL,
    plan public."UserPlan" DEFAULT 'FREE'::public."UserPlan" NOT NULL,
    plan_expires_at timestamp(3) without time zone,
    stripe_customer_id text,
    stripe_subscription_id text,
    is_invisible boolean DEFAULT false NOT NULL,
    plan_started_at timestamp(3) without time zone,
    bio text,
    certifications text[] DEFAULT ARRAY[]::text[],
    city text,
    country text,
    education jsonb,
    experience jsonb,
    github_url text,
    languages text[] DEFAULT ARRAY[]::text[],
    linkedin_url text,
    portfolio_url text,
    skills text[] DEFAULT ARRAY[]::text[],
    title text,
    website_url text,
    years_of_experience integer
);


ALTER TABLE public.users OWNER TO admin;

